// Enhanced HTML analysis with better page detection
let html = '';

try {
  html = $input.first().json.body || 
         $input.first().json.data || 
         $input.first().json || '';

  if (typeof html !== 'string') {
    html = String(html);
  }
} catch (error) {
  return {
    json: {
      error: 'Failed to get HTML',
      message: error.message
    }
  };
}

if (!html || html.length === 0) {
  return {
    json: {
      error: 'HTML content is empty'
    }
  };
}

const url = $('Submit Website URL for Analysis').first().json.URL || '';

// Extract all links more accurately
const linkRegex = /<a[^>]+href=["']([^"']+)["']/gi;
const allLinks = [];
let match;
while ((match = linkRegex.exec(html)) !== null) {
  allLinks.push(match[1].toLowerCase().trim());
}

// Normalize URLs - remove trailing slashes, query params, anchors
const normalizeUrl = (link) => {
  return link
    .split('?')[0]    // Remove query params
    .split('#')[0]    // Remove anchors
    .replace(/\/$/, '') // Remove trailing slash
    .toLowerCase();
};

const normalizedLinks = allLinks.map(normalizeUrl);

// Enhanced page detection with multiple patterns
const pagePatterns = {
  home: {
    patterns: [/(^\/|^index|^home)$/i, /homepage/i],
    keywords: ['home', 'homepage']
  },
  about: {
    patterns: [/about[-_]?(us|me|company)?/i, /who[-_]?we[-_]?are/i, /our[-_]?story/i],
    keywords: ['about us', 'about', 'our story', 'who we are', 'company']
  },
  contact: {
    patterns: [/contact[-_]?(us|me)?/i, /get[-_]?in[-_]?touch/i, /reach[-_]?us/i],
    keywords: ['contact', 'get in touch', 'reach us', 'contact us']
  },
  services: {
    patterns: [/services?/i, /what[-_]?we[-_]?do/i, /offerings?/i, /solutions?/i],
    keywords: ['services', 'service', 'what we do', 'solutions', 'offerings']
  },
  products: {
    patterns: [/products?/i, /shop/i, /store/i, /catalog/i],
    keywords: ['products', 'product', 'shop', 'store', 'catalog']
  },
  blog: {
    patterns: [/blog/i, /news/i, /articles?/i, /insights?/i],
    keywords: ['blog', 'news', 'articles', 'insights', 'posts']
  },
  portfolio: {
    patterns: [/portfolio/i, /work/i, /projects?/i, /case[-_]?studies/i],
    keywords: ['portfolio', 'our work', 'projects', 'case studies']
  },
  pricing: {
    patterns: [/pricing/i, /plans?/i, /packages?/i, /rates?/i],
    keywords: ['pricing', 'plans', 'packages', 'rates']
  },
  faq: {
    patterns: [/faq/i, /frequently[-_]?asked/i, /questions?/i],
    keywords: ['faq', 'frequently asked', 'questions']
  },
  testimonials: {
    patterns: [/testimonials?/i, /reviews?/i, /feedback/i, /client[-_]?stories/i],
    keywords: ['testimonials', 'reviews', 'feedback', 'client stories']
  },
  team: {
    patterns: [/team/i, /staff/i, /people/i, /our[-_]?team/i, /meet[-_]?the[-_]?team/i],
    keywords: ['team', 'our team', 'staff', 'people', 'meet the team']
  },
  careers: {
    patterns: [/careers?/i, /jobs?/i, /join[-_]?us/i, /employment/i, /hiring/i],
    keywords: ['careers', 'jobs', 'join us', 'employment', 'hiring']
  },
  privacy: {
    patterns: [/privacy[-_]?policy/i, /privacy/i],
    keywords: ['privacy policy', 'privacy']
  },
  terms: {
    patterns: [/terms[-_]?(and[-_]?conditions|of[-_]?service)?/i, /conditions/i],
    keywords: ['terms', 'terms and conditions', 'terms of service']
  }
};

const existingPages = [];
const missingPages = [];
const detectionDetails = {};

// Check each page type
Object.entries(pagePatterns).forEach(([pageName, config]) => {
  let found = false;
  const matches = [];

  // Check in URLs
  for (const link of normalizedLinks) {
    for (const pattern of config.patterns) {
      if (pattern.test(link)) {
        found = true;
        matches.push(`URL: ${link}`);
        break;
      }
    }
    if (found) break;
  }

  // Check in HTML content for keywords
  if (!found) {
    for (const keyword of config.keywords) {
      const keywordRegex = new RegExp(`<a[^>]+>\\s*${keyword}\\s*</a>`, 'gi');
      if (keywordRegex.test(html)) {
        found = true;
        matches.push(`Keyword: ${keyword}`);
        break;
      }
    }
  }

  detectionDetails[pageName] = {
    found: found,
    matches: matches
  };

  if (found) {
    existingPages.push(pageName);
  } else {
    missingPages.push(pageName);
  }
});

// Detect business type with better logic
let businessType = 'general';
if (html.match(/shop|ecommerce|cart|buy\s*now|add\s*to\s*cart|checkout/i)) {
  businessType = 'ecommerce';
} else if (html.match(/portfolio|designer|developer|freelance|creative\s*agency/i)) {
  businessType = 'portfolio / agency';
} else if (html.match(/blog|article|post|news/i) && !html.match(/services|products/i)) {
  businessType = 'blog / content site';
} else if (html.match(/saas|software|subscription|cloud\s*platform/i)) {
  businessType = 'saas / software';
} else if (html.match(/consulting|agency|marketing|media/i)) {
  businessType = 'service / agency';
}

// Extract metadata
const titleMatch = html.match(/<title>(.*?)<\/title>/i);
const title = titleMatch ? titleMatch[1].trim() : 'No title found';

const descMatch = html.match(/<meta\s+name=["']description["']\s+content=["']([^"']+)["']/i);
const description = descMatch ? descMatch[1].trim() : '';

return {
  json: {
    url: url,
    title: title,
    description: description,
    business_type: businessType,
    existing_pages: existingPages,
    missing_pages: missingPages,
    detection_details: detectionDetails,
    total_links: allLinks.length,
    html_length: html.length,
    ready_for_ai: true
  }
};
